import { MakeLogicType, actions, connect, kea, path, reducers, selectors } from 'kea'

import { organizationLogic } from 'scenes/organizationLogic'
import { userLogic } from 'scenes/userLogic'

import { TeamBasicType } from '~/types'

import type { OrganizationType, UserType } from '../../../types'

export type ProjectState = 'on' | 'off' | 'partial'

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface realtimeNotificationPreferencesLogicValues {
    currentOrganization: OrganizationType | null // organizationLogic
    user: UserType | null // userLogic
    activeTypes: string[]
    allOff: boolean
    allOn: boolean
    defaultExpanded: boolean
    disabledMap: Record<string, Record<string, boolean>>
    expandedOverrides: Record<number, boolean>
    isProjectExpanded: (teamId: number) => boolean
    isTypeEnabledForTeam: (type: string, teamId: number) => boolean
    projectState: (teamId: number) => ProjectState
    teamIds: number[]
    teams: TeamBasicType[]
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface realtimeNotificationPreferencesLogicActions {
    setProjectExpanded: (
        teamId: number,
        expanded: boolean
    ) => {
        expanded: boolean
        teamId: number
    }
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface realtimeNotificationPreferencesLogicMeta {
    __keaTypeGenInternalSelectorTypes: {
        teams: (currentOrganization: OrganizationType | null) => TeamBasicType[]
        teamIds: (teams: TeamBasicType[]) => number[]
        activeTypes: (user: UserType | null) => string[]
        disabledMap: (user: UserType | null) => Record<string, Record<string, boolean>>
        defaultExpanded: (teams: TeamBasicType[]) => boolean
        isProjectExpanded: (
            expandedOverrides: Record<number, boolean>,
            defaultExpanded: boolean
        ) => (teamId: number) => boolean
        isTypeEnabledForTeam: (
            disabledMap: Record<string, Record<string, boolean>>
        ) => (type: string, teamId: number) => boolean
        projectState: (
            activeTypes: string[],
            disabledMap: Record<string, Record<string, boolean>>
        ) => (teamId: number) => ProjectState
        allOn: (teamIds: number[], projectState: (teamId: number) => ProjectState) => boolean
        allOff: (teamIds: number[], projectState: (teamId: number) => ProjectState) => boolean
    }
}

export type realtimeNotificationPreferencesLogicType = MakeLogicType<
    realtimeNotificationPreferencesLogicValues,
    realtimeNotificationPreferencesLogicActions,
    Record<string, any>,
    realtimeNotificationPreferencesLogicMeta
>

export const realtimeNotificationPreferencesLogic = kea<realtimeNotificationPreferencesLogicType>([
    path(['scenes', 'settings', 'user', 'realtimeNotificationPreferencesLogic']),
    connect({
        values: [userLogic, ['user'], organizationLogic, ['currentOrganization']],
    }),
    actions({
        setProjectExpanded: (teamId: number, expanded: boolean) => ({ teamId, expanded }),
    }),
    reducers({
        expandedOverrides: [
            {} as Record<number, boolean>,
            {
                setProjectExpanded: (state, { teamId, expanded }) => ({ ...state, [teamId]: expanded }),
            },
        ],
    }),
    selectors(() => ({
        teams: [
            (s) => [s.currentOrganization],
            (currentOrganization: OrganizationType | null): TeamBasicType[] => currentOrganization?.teams ?? [],
        ],
        teamIds: [(s) => [s.teams], (teams: TeamBasicType[]): number[] => teams.map((t) => t.id)],
        activeTypes: [
            () => [userLogic.selectors.user],
            (user: null | import('~/types').UserType): string[] =>
                (user?.active_realtime_notification_types ?? []) as string[],
        ],
        disabledMap: [
            () => [userLogic.selectors.user],
            (user: null | import('~/types').UserType): Record<string, Record<string, boolean>> =>
                user?.notification_settings?.realtime_notifications_disabled ?? {},
        ],
        defaultExpanded: [(s) => [s.teams], (teams: TeamBasicType[]): boolean => teams.length <= 3],
        isProjectExpanded: [
            (s) => [s.expandedOverrides, s.defaultExpanded],
            (overrides: Record<number, boolean>, defaultExpanded: boolean) =>
                (teamId: number): boolean =>
                    overrides[teamId] ?? defaultExpanded,
        ],
        isTypeEnabledForTeam: [
            (s) => [s.disabledMap],
            (disabledMap: Record<string, Record<string, boolean>>) =>
                (type: string, teamId: number): boolean =>
                    !disabledMap[type]?.[String(teamId)],
        ],
        projectState: [
            (s) => [s.activeTypes, s.disabledMap],
            (activeTypes: string[], disabledMap: Record<string, Record<string, boolean>>) =>
                (teamId: number): ProjectState => {
                    if (activeTypes.length === 0) {
                        return 'on'
                    }
                    const enabledFlags = activeTypes.map((type) => !disabledMap[type]?.[String(teamId)])
                    if (enabledFlags.every((v) => v)) {
                        return 'on'
                    }
                    if (enabledFlags.every((v) => !v)) {
                        return 'off'
                    }
                    return 'partial'
                },
        ],
        allOn: [
            (s) => [s.teamIds, s.projectState],
            (teamIds: number[], projectState: (teamId: number) => ProjectState): boolean =>
                teamIds.every((teamId) => projectState(teamId) === 'on'),
        ],
        allOff: [
            (s) => [s.teamIds, s.projectState],
            (teamIds: number[], projectState: (teamId: number) => ProjectState): boolean =>
                teamIds.every((teamId) => projectState(teamId) === 'off'),
        ],
    })),
])
